code = """import json
import re
import pandas as pd

# Load all data files
packages_file = locals()['var_functions.query_db:14']
mappings_file = locals()['var_functions.query_db:12']  
projects_file = locals()['var_functions.query_db:22']

with open(packages_file, 'r') as f:
    all_pkg = json.load(f)

with open(mappings_file, 'r') as f:
    all_mappings = json.load(f)

with open(projects_file, 'r') as f:
    all_projects = json.load(f)

print('Loaded ' + str(len(all_pkg)) + ' packages')
print('Loaded ' + str(len(all_mappings)) + ' mappings')
print('Loaded ' + str(len(all_projects)) + ' projects')

# Process packages: find latest release for each
latest_releases = {}
for pkg in all_pkg:
    if pkg['System'] == 'NPM':
        try:
            vinfo = json.loads(pkg['VersionInfo'])
            if vinfo.get('IsRelease', False):
                name = pkg['Name']
                ordinal = vinfo.get('Ordinal', 0)
                version = pkg['Version']
                
                key = (pkg['System'], name)
                if key not in latest_releases or ordinal > latest_releases[key]['Ordinal']:
                    latest_releases[key] = {
                        'System': pkg['System'],
                        'Name': name,
                        'Version': version,
                        'Ordinal': ordinal
                    }
        except:
            continue

print('Found ' + str(len(latest_releases)) + ' latest NPM releases')

# Process projects: extract stars and create lookup
df_projects = pd.DataFrame(all_projects)
df_projects['ProjectName'] = df_projects['Project_Information'].apply(
    lambda x: re.search(r'(?:project|repository)\s+([a-zA-Z0-9_.-]+/[a-zA-Z0-9_.-]+)', x).group(1) 
              if re.search(r'(?:project|repository)\s+([a-zA-Z0-9_.-]+/[a-zA-Z0-9_.-]+)', x) else ''
)
df_projects['Stars'] = df_projects['Project_Information'].apply(
    lambda x: int(re.search(r'(\d+(?:,\d+)*)\s+stars', x).group(1).replace(',', '')) 
              if re.search(r'(\d+(?:,\d+)*)\s+stars', x) else 0
)

project_stars = dict(zip(df_projects['ProjectName'], df_projects['Stars']))
print('Processed ' + str(len([k for k,v in project_stars.items() if v > 0])) + ' projects with stars')

# Map packages to stars
package_stars = []
df_mappings = pd.DataFrame(all_mappings)

for key, pkg in latest_releases.items():
    # Find any mapping for this package (by System and Name)
    mappings = df_mappings[
        (df_mappings['System'] == pkg['System']) & 
        (df_mappings['Name'] == pkg['Name'])
    ]
    
    if not mappings.empty:
        project_name = mappings.iloc[0]['ProjectName']
        stars = project_stars.get(project_name, 0)
        if stars > 0:
            package_stars.append({
                'Name': pkg['Name'],
                'Version': pkg['Version'],
                'Stars': stars
            })

print('Mapped ' + str(len(package_stars)) + ' packages to stars')

# Get top 5
top5 = sorted(package_stars, key=lambda x: x['Stars'], reverse=True)[:5]

print('Top 5 NPM packages by stars:')
for pkg in top5:
    print('  ' + pkg['Name'] + ' v' + pkg['Version'] + ': ' + str(pkg['Stars']) + ' stars')

total_packages = len(latest_releases)
mapped_stars = len(package_stars)
msg = 'Processed ' + str(total_packages) + ' NPM packages, found ' + str(mapped_stars) + ' with GitHub data'
print(msg)

result = top5
print('__RESULT__:')
print(json.dumps(result))"""

